INSERT INTO `sample_sentences` (`id`,`article_id`,`technique`,`offsets`,`label`,`text`,`parseTree`,`date_updated`,`completed`) VALUES (595,'786527921','[9 5]','[array([ 90, 114]) array([164, 379])]',1,'The four page email begins with Murillo claiming she and others at Google were engaged in non-partisan activities not designed to help any one candidate or another—only to undercut her own commentary in later passages in the emails by openly admitting the entire effort to boost Latino turnout using Google products with official company resources was to elect Clinton over Trump.','(S (NP (DT The) (NML (CD four) (NN page)) (NN email)) (VP (VBZ begins) (PP (IN with) (S (NP (NNP Murillo)) (VP (VBG claiming) (SBAR (S (NP (NP (NP (PRP she)) (CC and) (NP (NNS others))) (PP (IN at) (NP (NNP Google)))) (VP (VBD were) (VP (VBN engaged) (PP (IN in) (NP (NP (ADJP (JJ non) (HYPH -) (JJ partisan)) (NNS activities)) (VP (RB not) (VBN designed) (S (VP (TO to) (VP (VB help) (NP (DT any) (CD one) (NN candidate) (CC or) (DT another)))))))) (: —) (S (ADVP (RB only)) (VP (TO to) (VP (VB undercut) (NP (PRP$ her) (JJ own) (NN commentary)) (PP (IN in) (NP (NP (JJ later) (NNS passages)) (PP (IN in) (NP (DT the) (NNS emails))))) (PP (IN by) (S (ADVP (RB openly)) (VP (VBG admitting) (SBAR (S (NP (DT the) (JJ entire) (NN effort) (S (VP (TO to) (VP (VB boost) (NP (NP (JJ Latino) (NN turnout)) (VBG using) (NP (NNP Google) (NNS products))) (PP (IN with) (NP (JJ official) (NN company) (NNS resources))))))) (VP (VBD was) (S (VP (TO to) (VP (VB elect) (NP (NNP Clinton)) (PP (IN over) (NP (NNP Trump))))))))))))))))))))))) (. .))','2023-06-23 00:00:00',0);
