INSERT INTO `sample_sentences` (`id`,`article_id`,`technique`,`offsets`,`label`,`text`,`parseTree`,`date_updated`,`completed`) VALUES (3387,'783702663','[ 8  9 13  8  9]','[array([129, 148]) array([166, 261]) array([166, 261]) array([292, 328])  array([353, 412])]',1,'This will be a final victory over the enemies within and their apologists, such as Faggioli, who, in typical neo-Catholic style, imperiously scoffs at the notion of “a young clergy marked by personal sanctity but also by a fascination for a mythical Middle Ages” and busies himself defending an unsalvageable mass of corruption he dares to describe as “a Church-world relationship based on a principle of reality.”','(S (NP (DT This)) (VP (MD will) (VP (VB be) (NP (NP (DT a) (JJ final) (NN victory)) (PP (IN over) (NP (NP (NP (DT the) (NNS enemies)) (IN within)) (CC and) (NP (NP (PRP$ their) (NNS apologists)) (, ,) (PP (JJ such) (IN as) (NP (NP (NNP Faggioli)) (, ,) (SBAR (WHNP (WP who)) (, ,) (S (PP (IN in) (NP (JJ typical) (ADJP (JJ neo) (HYPH -) (JJ Catholic)) (NN style))) (, ,) (ADVP (RB imperiously)) (VP (VP (VBZ scoffs) (PP (IN at) (NP (NP (DT the) (NN notion)) (PP (PP (IN of) (`` “) (NP (NP (DT a) (JJ young) (NN clergy)) (VP (VBN marked) (PP (PP (IN by) (NP (JJ personal) (NN sanctity))) (CC but) (RB also) (PP (IN by) (NP (NP (DT a) (NN fascination)) (PP (IN for) (NP (DT a) (JJ mythical) (NNP Middle) (NNPS Ages))))))))) (\'\' ”))))) (CC and) (VP (VBZ busies) (NP (PRP himself)) (S (VP (VBG defending) (NP (NP (NP (DT an) (JJ unsalvageable) (NN mass)) (PP (IN of) (NP (NN corruption)))) (SBAR (S (NP (PRP he)) (VP (VBZ dares) (S (VP (TO to) (VP (VB describe) (PP (IN as) (`` “) (NP (NP (DT a) (NML (NNP Church) (HYPH -) (NN world)) (NN relationship)) (VP (VBN based) (PP (IN on) (NP (NP (DT a) (NN principle)) (PP (IN of) (NP (NN reality))))))))))))))))))))))))))))) (. .) (. ”))','2023-06-23 00:00:00',0);
