INSERT INTO `sample_sentences` (`id`,`article_id`,`technique`,`offsets`,`label`,`text`,`parseTree`,`date_updated`,`completed`) VALUES (3796,'711566593','[11 17]','[array([ 25, 200]) array([ 25, 201])]',1,'Let me just remind them, they are themselves under investigation by a special prosecutor in Washington D.C. and they may soon avail themselves of the presumption of innocence beyond a reasonable doubt, so I ask that they reflect on that before they comment or disparage the results of this case.”','(S (S (VP (VB Let) (S (NP (PRP me)) (ADVP (RB just)) (VP (VB remind) (NP (PRP them)) (, ,) (SBAR (S (S (NP (PRP they)) (VP (VBP are) (NP (PRP themselves)) (PP (IN under) (NP (NP (NN investigation)) (PP (IN by) (NP (NP (DT a) (JJ special) (NN prosecutor)) (PP (IN in) (NP (NNP Washington) (NNP D.C.))))))))) (CC and) (S (NP (PRP they)) (VP (MD may) (ADVP (RB soon)) (VP (VB avail) (NP (PRP themselves)) (PP (IN of) (NP (NP (DT the) (NN presumption)) (PP (IN of) (NP (NN innocence))))) (PP (IN beyond) (NP (DT a) (JJ reasonable) (NN doubt)))))))))))) (, ,) (IN so) (S (NP (PRP I)) (VP (VBP ask) (SBAR (IN that) (S (NP (PRP they)) (VP (VB reflect) (PP (IN on) (NP (DT that))) (SBAR (IN before) (S (NP (PRP they)) (VP (VBP comment) (CC or) (VBP disparage) (NP (NP (DT the) (NNS results)) (PP (IN of) (NP (DT this) (NN case)))))))))))) (. .) (\'\' ”))','2023-06-23 00:00:00',0);
