INSERT INTO `sample_sentences` (`id`,`article_id`,`technique`,`offsets`,`label`,`text`,`parseTree`,`date_updated`,`completed`) VALUES (3798,'701837665','[ 6  4 11]','[array([42, 97]) array([170, 308]) array([368, 389])]',1,'In other words, unlike Lee Harvey Oswald, who had absolutely no motive to kill President Kennedy, the national security establishment did have motive, a powerful motive, the same motive that motivated the CIA and Pentagon to target other political leaders for regime change or assassination around that time, such as Mohamad Mossadegh, Jacobo Arbenz, Patrice Lumumba (who Kennedy admired), Fidel Castro, and Salvador Allende.','(S (PP (IN In) (NP (JJ other) (NNS words))) (, ,) (PP (IN unlike) (NP (NP (NNP Lee) (NNP Harvey) (NNP Oswald)) (, ,) (SBAR (WHNP (WP who)) (S (VP (VBD had) (NP (ADJP (RB absolutely) (DT no)) (NN motive) (S (VP (TO to) (VP (VB kill) (NP (NNP President) (NNP Kennedy))))))))))) (, ,) (NP (DT the) (NML (JJ national) (NN security)) (NN establishment)) (VP (VBD did) (VP (VB have) (NP (NP (NN motive)) (, ,) (NP (DT a) (JJ powerful) (NN motive)) (, ,) (NP (NP (DT the) (JJ same) (NN motive)) (SBAR (WHNP (WDT that)) (S (VP (VBD motivated) (NP (DT the) (NNP CIA) (CC and) (NP (NNP Pentagon))) (S (VP (TO to) (VP (VB target) (NP (JJ other) (JJ political) (NNS leaders)) (PP (IN for) (NP (NP (NN regime) (NN change)) (CC or) (NP (NN assassination)))) (PP (IN around) (NP (DT that) (NN time))) (, ,) (PP (JJ such) (IN as) (NP (NP (NNP Mohamad) (NNP Mossadegh)) (, ,) (NP (NNP Jacobo) (NNP Arbenz)) (, ,) (NP (NP (NNP Patrice) (NNP Lumumba)) (-LRB- -LRB-) (SBAR (WHNP (WP who)) (S (NP (NNP Kennedy)) (VP (VBD admired))))) (, -RRB-) (, ,) (NP (NNP Fidel) (NNP Castro)) (, ,) (CC and) (NP (NNP Salvador) (NNP Allende)))))))))))))) (. .))','2023-06-23 00:00:00',0);
INSERT INTO `sample_sentences` (`id`,`article_id`,`technique`,`offsets`,`label`,`text`,`parseTree`,`date_updated`,`completed`) VALUES (3799,'701837665','[ 7 11  9]','[array([189, 220]) array([221, 263]) array([315, 324])]',1,'After Oswald supposedly tried to defect to the Soviet Union and promised U.S. Embassy officials in Moscow that he was going to deliver classified information to the Soviet Union, which was America’s sworn Cold War enemy (and former World War II partner and ally), U.S. officials permitted him to return home with a Red wife, without even one grand-jury summons or even an iota of harassment.','(S (SBAR (IN After) (S (NP (NNP Oswald)) (ADVP (RB supposedly)) (VP (VP (VBD tried) (S (VP (TO to) (VP (VB defect) (PP (IN to) (NP (DT the) (NNP Soviet) (NNP Union))))))) (CC and) (VP (VBD promised) (NP (NP (NML (NNP U.S.) (NNP Embassy)) (NNS officials)) (PP (IN in) (NP (NNP Moscow)))) (SBAR (IN that) (S (NP (PRP he)) (VP (VBD was) (VP (VBG going) (S (VP (TO to) (VP (VB deliver) (NP (JJ classified) (NN information)) (PP (IN to) (NP (NP (DT the) (NNP Soviet) (NNP Union)) (, ,) (SBAR (WHNP (WDT which)) (S (VP (VBD was) (NP (NP (NP (NNP America) (POS ’s)) (JJ sworn) (NML (NNP Cold) (NNP War)) (NN enemy)) (-LRB- -LRB-) (CC and) (NP (JJ former) (NML (NNP World) (NNP War) (NNP II)) (NN partner) (CC and) (NN ally)) (-RRB- -RRB-)))))))))))))))))) (, ,) (NP (NNP U.S.) (NNS officials)) (VP (VBD permitted) (NP (PRP him)) (S (VP (TO to) (VP (VB return) (ADVP (RB home)) (PP (IN with) (NP (DT a) (NNP Red) (NN wife))) (, ,) (PP (IN without) (NP (NP (NP (QP (RB even) (CD one)) (NML (JJ grand) (HYPH -) (NN jury)) (NNS summons)) (CC or) (NP (RB even) (NP (DT an) (NN iota)))) (PP (IN of) (NP (NN harassment))))))))) (. .))','2023-06-23 00:00:00',0);
